class Parent {
    protected void show() {
        System.out.println("Parent show");
    }
}
class Child extends Parent {
    @Override
    public void show() {
        System.out.println("Child show");
    }
}
public class Test {
    public static void main(String[] args) {
        Parent p = new Child();
        p.show();  // 输出 Child show
    }
}
