class Box<T extends Comparable<T>> {
    private List<T> items = new ArrayList<>();

    public void add(T item) {
        items.add(item);
    }

    public T get(int index) {
        return items.get(index);
    }

    public void sort() {
        Collections.sort(items);
    }

    @Override
    public String toString() {
        return items.toString();
    }
}

// 测试
